impl LaunchConfig {
    /// Creates a 1-D launch configuration for `n` elements.
    ///
    /// Uses a block size of 256 threads and computes the grid size via
    /// ceiling division. No dynamic shared memory is requested.
    ///
    /// Suitable for simple element-wise kernels where thread index maps
    /// directly to element index. The helper does not inspect a kernel, so it
    /// does not by itself make a raw launch safe.
    pub fn for_num_elems(n: u32) -> Self {
        const DEFAULT_BLOCK_SIZE: u32 = 256;
        let grid_x = n.div_ceil(DEFAULT_BLOCK_SIZE);
        LaunchConfig {
            grid_dim: (grid_x, 1, 1),
            block_dim: (DEFAULT_BLOCK_SIZE, 1, 1),
            shared_mem_bytes: 0,
        }
    }
}

mod sealed {
    pub trait Sealed {}
}

/// A rank-preserving launch configuration accepted by a typed kernel contract.
///
/// This trait is sealed. Use [`LaunchConfig1D`], [`LaunchConfig2D`], or
/// [`LaunchConfig3D`]; downstream crates cannot provide a configuration that
/// bypasses their fixed trailing dimensions.
pub trait KernelLaunchConfig: sealed::Sealed + Copy {

/// Real `index_1d` intrinsic the `#[kernel]` / `#[device]` macros call in
/// place of the public `super::index_1d` stub. Returns
/// `blockIdx.x * blockDim.x + threadIdx.x`.
///
/// Unique per thread **only for a 1D launch** (`blockDim.y == blockDim.z ==
/// 1` and `gridDim.y == gridDim.z == 1`); a 2D/3D launch collides because
/// this reads only the X registers. A prepared `domain = 1` launch enforces
/// those trailing dimensions; a raw launch must prove them explicitly.
#[inline(always)]
pub fn index_1d<'kernel>(
    scope: &'kernel KernelScope<'kernel>,
) -> ThreadIndex<'kernel, Index1D> {
    let tid = super::threadIdx_x() as usize;
    let bid = super::blockIdx_x() as usize;
    let bdim = super::blockDim_x() as usize;
    unsafe { ThreadIndex::new(bid * bdim + tid, scope) }
}

/// Real `index_2d::<ROW_STRIDE>` intrinsic the macros call in place of the
/// public `super::index_2d` stub. `Some(row * ROW_STRIDE + col)` when
/// `col < ROW_STRIDE`, else `None`. Unique per thread for a 2D launch
/// (`blockDim.z == gridDim.z == 1`); the const stride is in the witness type.
#[inline(always)]
pub fn index_2d<'kernel, const ROW_STRIDE: usize>(
    scope: &'kernel KernelScope<'kernel>,
) -> Option<ThreadIndex<'kernel, Index2D<ROW_STRIDE>>> {
    let row = (super::blockIdx_y() as usize) * (super::blockDim_y() as usize)
        + (super::threadIdx_y() as usize);

